package com.shanfuchun.courtassistant.service.parser.cleaner

import java.util.regex.Pattern

/**
 * OCR噪声清理器
 *
 * 负责清理OCR识别过程中产生的各种噪声：
 * - 乱括号（数字周围的括号）
 * - 换行符干扰
 * - 年份和案件号的多余数字
 * - 多余空格
 *
 * 特殊保护：
 * - 保留案件号括号：(2024)
 * - 保留日期格式的完整性
 */
object OcrNoiseCleaner {

    /**
     * 清理OCR识别的文本噪声
     *
     * @param text 原始文本
     * @return 清理后的文本
     */
    fun clean(text: String): String {
        var cleaned = text.replace("\r\n", "\n").replace("\r", "\n")

        // 1. 合并换行符为空格
        cleaned = cleaned.replace("\n", " ")

        // 2. 保护案件号括号：(2024) 或 （2024）
        cleaned = cleaned.replace(Regex("[（(](\\d{4})[）)]"), "【CASE\\1】")

        // 3. 移除数字周围的括号/方括号：(14) [7]
        cleaned = cleaned.replace(Regex("[\\[（(]\\s*(\\d+)\\s*[\\]）)]"), "$1")

        // 4. 移除数字前的孤立的左括号：(14
        cleaned = cleaned.replace(Regex("[\\[（(]\\s*(\\d+)"), "$1")

        // 5. 移除数字后的孤立的右括号：14)
        cleaned = cleaned.replace(Regex("(\\d+)\\s*[\\]）)]"), "$1")

        // 6. 恢复案件号括号
        cleaned = cleaned.replace(Regex("【CASE(\\d{4})】"), "($1)")

        // 7. 修复年份多余数字：20261年 -> 2026年
        cleaned = cleaned.replace(Regex("(\\d{4})\\d(年)"), "$1$2")

        // 8. 修复案件号多余数字：38161号1 -> 38161号
        cleaned = cleaned.replace(Regex("(号)\\d(\\s)"), "$1$2")

        // 9. 合并多个空格
        cleaned = cleaned.replace(Regex("\\s+"), " ").trim()

        return cleaned
    }
}

package com.shanfuchun.courtassistant.service.parser.extractor

import com.shanfuchun.courtassistant.service.parser.pattern.CaseNoPattern

/**
 * 案件号提取器
 *
 * 从文本中提取案件号，支持多种格式：
 * - 标准格式：(2024)鲁1312民初4967号
 * - 宽松格式：年份被OCR识别错误
 * - 无括号格式：OCR去掉括号的情况
 */
class CaseNoExtractor {

    /**
     * 提取案件号
     *
     * @param text 输入文本
     * @return 提取到的案件号，如果未找到则返回空字符串
     */
    fun extract(text: String): String {
        // 尝试标准模式
        val standardMatch = CaseNoPattern.STANDARD.matcher(text)
        if (standardMatch.find()) {
            return standardMatch.group().replace("\\s+".toRegex(), "")
        }

        // 尝试宽松模式（带括号）
        val looseMatch = CaseNoPattern.SIMPLE.matcher(text)
        if (looseMatch.find()) {
            return looseMatch.group().replace("\\s+".toRegex(), "")
        }

        // 尝试无括号模式
        val noParenMatch = CaseNoPattern.NO_PAREN.matcher(text)
        if (noParenMatch.find()) {
            val noParenText = noParenMatch.group().replace("\\s+".toRegex(), "")
            // 添加括号：(2024鲁1312民初4967号)
            return "(" + noParenText.replaceFirst(Regex("^(\\d{4})"), "$1)") + ")"
        }

        return ""
    }
}

