/**
 * 法院名称提取器
 *
 * 从文本中提取法院名称
 */
class CourtNameExtractor {

    /**
     * 提取法院名称
     *
     * @param text 输入文本
     * @return 提取到的法院名称，如果未找到则返回空字符串
