    }
}

package com.shanfuchun.courtassistant.parser.text

import com.shanfuchun.courtassistant.parser.text.cleaner.OcrNoiseCleaner
import com.shanfuchun.courtassistant.parser.text.extractor.CaseNoExtractor
import com.shanfuchun.courtassistant.parser.text.extractor.CourtNameExtractor
import com.shanfuchun.courtassistant.parser.text.extractor.LocationExtractor
import com.shanfuchun.courtassistant.parser.text.extractor.PartyNameExtractor
import com.shanfuchun.courtassistant.parser.text.extractor.JudgeNameExtractor
