/**
 * 统一文本解析入口类
 * 负责协调各个解析器组件，提供完整的案件信息解析功能
 */
data class HearingInfo(
    val hearingTime: Long = 0,
    val courtName: String = "",
    val caseNo: String = "",
    val location: String = "",
    val partyName: String = "",
    val judge: String = ""
)

class TextParser {

    private val cleaner = OcrNoiseCleaner()
    private val timeExtractor = TimeExtractor()
    private val courtNameExtractor = CourtNameExtractor()
    private val caseNoExtractor = CaseNoExtractor()
    private val locationExtractor = LocationExtractor()
    private val partyNameExtractor = PartyNameExtractor()
    private val judgeNameExtractor = JudgeNameExtractor()

    /**
     * 解析文本内容，提取案件信息
     * @param text 原始文本内容
     * @return HearingInfo 包含案件信息的对象
     */
    fun parse(text: String): HearingInfo {
        val normalized = cleaner.clean(text)
        return HearingInfo(
            hearingTime = timeExtractor.extract(normalized),
            courtName = courtNameExtractor.extract(normalized),
            caseNo = caseNoExtractor.extract(normalized),
            location = locationExtractor.extract(normalized),
            partyName = partyNameExtractor.extract(normalized),
            judge = judgeNameExtractor.extract(normalized)
        )
    }

    /**
     * 从文本中提取所有URL链接
     * @param text 原始文本内容
     * @return List<String> URL列表
     */
    fun extractUrls(text: String): List<String> {
        return URL_PATTERN.find(text)?.mapNotNull { it.value } ?: emptyList()
    }

    companion object {
        /**
         * URL正则模式
         */
        private val URL_PATTERN = Regex("https?://[\\w\\-._~:/?#\\[\\]@!$&'()*+,;=%]+")
    }
}

package com.shanfuchun.courtassistant.parser.text.pattern

/**
 * 法院名称正则模式定义
 * 支持各种法院名称的格式
 */
object CourtNamePattern {

    /**
     * 法院标准正则模式
     * 匹配包含特定后缀的法院名称
     */
    val STANDARD = Regex("[\\u4e00-\\u9fa5]+(?:人民法院|人民法庭|人\\s*法院|仲裁委员会|仲裁院)")
}

package com.shanfuchun.courtassistant.parser.text.pattern

/**
 * 地点正则模式定义
 * 支持不同类型的案件地点信息
 */
object LocationPattern {

    /**
     * 传票中"应到处所"字段正则模式
     * 允许换行后出现值的情况
     */
    val SUMMONS = Regex(
        "应到处所[\\s：:]*([\\u4e00-\\u9fa5\\d\\-—号楼层室A-Za-z第]+(?:审判庭|法庭|法院|室|庭))"
    )

    /**
     * 短信通知中"在...开庭"正则模式
     * 允许"法 庭"等带空格的情况
     */
    val SMS = Regex(
        "在([\\u4e00-\\u9fa5\\d第]+(?:审\\s*判\\s*庭|法\\s*庭|法\\s*院|处\\s*所|室|庭))"
    )

    /**
     * 通用地点正则模式
     * 匹配地点、法庭等字段的值
     */
    val GENERIC = Regex(
        "(?:地[点址]|法庭|审判庭|处所)[：:为在]\\s*([\\u4e00-\\u9fa5\\d\\-—号楼层室第A-Za-z]+)"
    )
}

package com.shanfuchun.courtassistant.parser.text.pattern

/**
 * 审判员名称正则模式定义
 * 支持带括号的审判员姓名格式
 */
object JudgeNamePattern {

    /**
     * 审判员/联系人正则模式
     * 支持括号包裹的姓名，如"联系人 (刘国良)"
     */
    val STANDARD = Regex(
        "(?:承办人|联系人|审判员)[\\s：:]*[（(]?([\\u4e00-\\u9fa5]{2,6})[）)]?"
    )
}

package com.shanfuchun.courtassistant.parser.text.pattern

/**
 * URL正则模式定义
 * 用于提取文本中的网络链接
 */
object UrlPattern {

    /**
     * 标准URL正则模式
     * 匹配HTTP和HTTPS协议的URL
     */
    val STANDARD = Regex("https?://[\\w\\-._~:/?#\\[\\]@!$&'()*+,;=%]+")
}

package com.shanfuchun.courtassistant.parser.text.extractor

import com.shanfuchun.courtassistant.parser.text.pattern.CaseNoPattern

/**
 * 案件号提取器
 * 负责从文本中提取案件号信息
 */
class CaseNoExtractor {

    /**
     * 从文本中提取案件号
     * 按照优先级依次尝试不同的匹配模式
     * @param text 处理后的文本
     * @return String 案件号，如果未找到则返回空字符串
     */
    fun extract(text: String): String {
        // 尝试标准模式
        CaseNoPattern.STANDARD.find(text)?.let { match ->
            return match.value.replace("\\s+".toRegex(), "")
        }

        // 尝试括号模式
        CaseNoPattern.LOOSE.find(text)?.let { match ->
            return match.value.replace("\\s+".toRegex(), "")
        }

        // 尝试无括号模式（OCR识别失败时）
        CaseNoPattern.NO_PARENS.find(text)?.let { match ->
            val cleaned = match.value.replace("\\s+".toRegex(), "")
            // 重新添加括号
            return cleaned.replaceFirst(Regex("^(\\d{4})"), "($1)")
        }

        return ""
    }
}

