package com.shanfuchun.courtassistant.parser.text.extractor

import com.shanfuchun.courtassistant.parser.text.pattern.LocationPattern

/**
 * 地点提取器
 * 负责从文本中提取开庭地点信息
 */
class LocationExtractor {

    /**
     * 从文本中提取地点信息
     * 按照优先级依次尝试不同的匹配模式
     * @param text 处理后的文本
     * @return String 地点信息，如果未找到则返回空字符串
     */
    fun extract(text: String): String {
        val patterns = listOf(
            LocationPattern.SUMMONS,
            LocationPattern.SMS,
            LocationPattern.GENERIC
        )

        for (pattern in patterns) {
            pattern.find(text)?.let { match ->
                return match.groupValues.getOrNull(1)?.replace(" ".toRegex(), "")?.trim() ?: ""
            }
        }

        return ""
    }
}

package com.shanfuchun.courtassistant.parser.text.extractor

import com.shanfuchun.courtassistant.parser.text.pattern.PartyNamePattern

/**
 * 当事人名称提取器
 * 负责从文本中提取当事人名称信息
 */
class PartyNameExtractor {

    /**
     * 黑名单关键词，排除匹配到的无效内容
     */
    private val BLACKLIST = listOf("传票", "经传", "传唤")

    /**
     * 从文本中提取当事人名称
     * @param text 处理后的文本
     * @return String 当事人名称，如果未找到则返回空字符串
     */
    fun extract(text: String): String {
        val patterns = listOf(
            PartyNamePattern.SUMMONS,
            PartyNamePattern.GENERIC
        )

        for (pattern in patterns) {
            pattern.find(text)?.let { match ->
                val value = match.groupValues.getOrNull(1)?.trim() ?: ""
                // 检查黑名单
                if (BLACKLIST.none { value.contains(it) }) {
                    return value
                }
            }
        }

        return ""
    }
}

