package com.shanfuchun.courtassistant.parser.text.extractor

import com.shanfuchun.courtassistant.parser.text.pattern.TimePattern
import java.util.Calendar
import java.util.TimeZone

/**
 * 时间提取器
 * 负责从文本中提取开庭时间信息
 */
class TimeExtractor {

    /**
     * 从文本中提取时间戳
     * 按照优先级依次尝试不同的时间格式
     * @param text 处理后的文本
     * @return Long 时间戳（毫秒），如果未找到则返回0
     */
    fun extract(text: String): Long {
        for (index in TimePattern.PATTERNS.indices) {
            val pattern = TimePattern.PATTERNS[index]
            pattern.find(text)?.let { match ->
                val timestamp = parseMatchToTime(match, index)
                if (timestamp > 0) return timestamp
            }
        }
        return 0
    }

    /**
     * 验证日期时间的有效性
     */
    private fun validDate(month: Int, day: Int, hour: Int, minute: Int): Boolean {
        return month in 1..12 && day in 1..31 && hour in 0..23 && minute in 0..59
    }

    /**
     * 将正则匹配结果转换为时间戳
     */
    private fun parseMatchToTime(match: MatchResult, patternIndex: Int): Long {
        val calendar = Calendar.getInstance(TimeZone.getTimeZone("Asia/Shanghai"))

        try {
            when (patternIndex) {
                0 -> { // 2024年07月12日 10:00
                    val year = match.groups[1]!!.value.toInt()
                    val month = match.groups[2]!!.value.toInt()
                    val day = match.groups[3]!!.value.toInt()
                    val hour = match.groups[4]!!.value.toInt()
                    val minute = match.groups[5]!!.value.toInt()
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(year, month - 1, day, hour, minute, 0)
                }
                1, 6 -> { // 2026年3月12日15时30分 / 定于...
                    val year = match.groups[1]!!.value.toInt()
                    val month = match.groups[2]!!.value.toInt()
                    val day = match.groups[3]!!.value.toInt()
                    val hour = match.groups[4]!!.value.toInt()
                    val minute = match.groups[5]?.value?.toIntOrNull() ?: 0
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(year, month - 1, day, hour, minute, 0)
                }
                2 -> { // 2026年3月12日 上午/下午 3点30分
                    val year = match.groups[1]!!.value.toInt()
                    val month = match.groups[2]!!.value.toInt()
                    val day = match.groups[3]!!.value.toInt()
                    var hour = match.groups[5]!!.value.toInt()
                    val period = match.groups[4]!!.value
                    // 处理上午/下午时间转换
                    if (period == "下午" || period == "晚上") {
                        if (hour < 12) hour += 12
                    } else if (period == "上午" && hour == 12) {
                        hour = 0
                    }
                    val minute = match.groups[6]?.value?.toIntOrNull() ?: 0
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(year, month - 1, day, hour, minute, 0)
                }
                3 -> { // 2026-03-12 15:00
                    val year = match.groups[1]!!.value.toInt()
                    val month = match.groups[2]!!.value.toInt()
                    val day = match.groups[3]!!.value.toInt()
                    val hour = match.groups[4]!!.value.toInt()
                    val minute = match.groups[5]!!.value.toInt()
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(year, month - 1, day, hour, minute, 0)
                }
                4 -> { // 3月12日15时30分
                    val month = match.groups[1]!!.value.toInt()
                    val day = match.groups[2]!!.value.toInt()
                    val hour = match.groups[3]!!.value.toInt()
                    val minute = match.groups[4]?.value?.toIntOrNull() ?: 0
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(Calendar.MONTH, month - 1)
                    calendar.set(Calendar.DAY_OF_MONTH, day)
                    calendar.set(Calendar.HOUR_OF_DAY, hour)
                    calendar.set(Calendar.MINUTE, minute)
                    calendar.set(Calendar.SECOND, 0)
                }
                5 -> { // 3月12日 下午3点
                    val month = match.groups[1]!!.value.toInt()
                    val day = match.groups[2]!!.value.toInt()
                    var hour = match.groups[4]!!.value.toInt()
                    val period = match.groups[3]!!.value
                    // 处理上午/下午时间转换
                    if (period == "下午" || period == "晚上") {
                        if (hour < 12) hour += 12
                    } else if (period == "上午" && hour == 12) {
                        hour = 0
                    }
                    val minute = match.groups[5]?.value?.toIntOrNull() ?: 0
                    if (!validDate(month, day, hour, minute)) return 0
                    calendar.set(Calendar.MONTH, month - 1)
                    calendar.set(Calendar.DAY_OF_MONTH, day)
                    calendar.set(Calendar.HOUR_OF_DAY, hour)
                    calendar.set(Calendar.MINUTE, minute)
                    calendar.set(Calendar.SECOND, 0)
                }
            }

            calendar.set(Calendar.MILLISECOND, 0)
            return calendar.timeInMillis
        } catch (e: Exception) {
            return 0
        }
    }
}

package com.shanfuchun.courtassistant.parser.text.cleaner

/**
 * OCR噪声清理器
 * 负责清理OCR识别产生的各种噪声和错误
 */
class OcrNoiseCleaner {

    /**
     * 清理OCR识别噪声
     * 处理内容包括：
     * - 数字周围的乱括号
     * - 字段中间的换行符
     * - 年份/案件号末尾的多余数字
     * 保留案件号括号如 (2024)
     * @param text 原始文本
     * @return String 清理后的文本
     */
    fun clean(text: String): String {
        var cleaned = text
            .replace("\r\n", "\n")
            .replace("\r", "\n")

        // 合并行
        cleaned = cleaned.replace("\n", " ")

        // 保护案件号括号：(2024) 或 （2024）— 标记它们
        cleaned = cleaned.replace(Regex("[（(](\\d{4})[）)]"), "【CASE\\1】")

        // 移除包裹数字的括号/方括号：(14) [7]
        cleaned = cleaned.replace(Regex("[\\[（(]\\s*(\\d+)\\s*[\\]）)]"), "$1")

        // 移除数字前的孤立开括号：[(
        cleaned = cleaned.replace(Regex("[\\[（(]\\s*(\\d+)"), "$1")

        // 移除数字后的孤立闭括号：)]
        cleaned = cleaned.replace(Regex("(\\d+)\\s*[\\]）)]"), "$1")

        // 恢复案件号括号
        cleaned = cleaned.replace(Regex("【CASE(\\d{4})】"), "($1)")

        // 修复年份后多余数字：20261年 -> 2026年
        cleaned = cleaned.replace(Regex("(\\d{4})\\d(年)"), "$1$2")

        // 修复案件号后多余数字：38161号1 -> 38161号
        cleaned = cleaned.replace(Regex("(号)\\d(\\s)"), "$1$2")

        // 合并多个空格
        cleaned = cleaned.replace(Regex("\\s+"), " ").trim()

        return cleaned
    }
}
